function lists(values=appState.bottles){return `<datalist id="bottles">${values.map(x=>`<option value="${esc(x)}">`).join('')}</datalist>`}
async function resizePhoto(file){return new Promise((resolve,reject)=>{const img=new Image(),reader=new FileReader();reader.onerror=reject;reader.onload=()=>{img.onload=()=>{const max=700,scale=Math.min(1,max/Math.max(img.width,img.height)),canvas=document.createElement('canvas');canvas.width=Math.round(img.width*scale);canvas.height=Math.round(img.height*scale);canvas.getContext('2d').drawImage(img,0,0,canvas.width,canvas.height);canvas.toBlob(blob=>blob?resolve(blob):reject(Error('Impossibile preparare la foto')),'image/jpeg',.76)};img.onerror=()=>reject(Error('Formato foto non leggibile'));img.src=reader.result};reader.readAsDataURL(file)})}
async function uploadBottlePhoto(file,code){const blob=await resizePhoto(file),safe=code.replace(/[^a-zA-Z0-9_-]/g,'_'),path=`${safe}.jpg`;const {error}=await db.storage.from('bottle-photos').upload(path,blob,{contentType:'image/jpeg',upsert:true});if(error)throw error;const {data}=db.storage.from('bottle-photos').getPublicUrl(path);return `${data.publicUrl}?v=${Date.now()}`}
