function setBottleLineChecks(code=''){const assigned=appState.bottleLines[code]||[selected];document.querySelectorAll('[name="mapBottleLine"]').forEach(input=>input.checked=assigned.includes(input.value));const all=$('#mapAllLines');if(all)all.checked=names.every(name=>assigned.includes(name))}
