function fillBottleDetails(code){const b=code.trim(),known=appState.bottles.includes(b);setBottleLineChecks(known?b:'');if(!known)return;$('#mapName').value=appState.bottleNames[b]||'';const p=$('#photoPreview');if(appState.bottleImages[b]){p.src=appState.bottleImages[b];p.hidden=false}else{p.removeAttribute('src');p.hidden=true}}
function previewSelectedBottle(code){const b=code.trim(),p=$('#selectedBottlePreview');if(!p)return;if(!appState.bottles.includes(b)){p.innerHTML='';return}p.innerHTML=`<div class="bottle-preview-row">${appState.bottleImages[b]?`<img src="${appState.bottleImages[b]}" alt="Foto flacone">`:'<span class="no-photo mini">Foto</span>'}<span><b>${esc(appState.bottleNames[b]||'Flacone')}</b><br>${esc(b)}</span></div>`}
async function saveBottleDetails(){try{if(!isCT())return toast('Operazione non autorizzata',true);const b=$('#mapBottle').value.trim(),n=$('#mapName').value.trim(),f=$('#mapPhoto').files[0],lineValues=[...document.querySelectorAll('[name="mapBottleLine"]:checked')].map(input=>input.value);if(!b||!n)return toast('Inserisci nome e codice',true);if(!lineValues.length)return toast('Scegli almeno una linea',true);toast(f?'Caricamento foto in corso…':'Salvataggio in corso…');appState.bottleNames[b]=n;if(f)appState.bottleImages[b]=await uploadBottlePhoto(f,b);if(!appState.bottles.includes(b))appState.bottles.push(b);appState.bottleLines[b]=lineValues;Object.values(appState.lines).filter(l=>l.bottle===b).forEach(l=>{l.bottleName=n;l.bottleImage=appState.bottleImages[b]||''});await save();const dialog=$('#bottleEditorDialog');if(dialog)dialog.close();render();toast(`Flacone salvato per ${lineValues.length===names.length?'tutte le linee':lineValues.join(', ')}`)}catch(e){toast(e.message||'Foto non salvata',true)}}
