function bottleArchive(){if(!isCT())return'';const codes=archiveCodes();return `<details class="archive-details"><summary><strong>Archivio ${archiveScope==='line'?`linea ${selected}`:'di tutti i flaconi'} (${codes.length})</strong></summary><div class="scope-actions"><button class="${archiveScope==='line'?'primary':''}" onclick="setArchiveScope('line')">Linea ${selected}</button><button class="${archiveScope==='all'?'primary':''}" onclick="setArchiveScope('all')">Tutti i flaconi</button></div><label class="field archive-target">Carica il codice sulla linea<select id="archiveTargetLine"><option value="${selected}">Linea ${selected}</option>${names.filter(name=>name!==selected).map(name=>`<option value="${name}">Linea ${name}</option>`).join('')}<option value="all">Tutte le linee</option></select></label><div class="archive-grid">${codes.length?codes.map(b=>`<div class="archive-card">${appState.bottleImages[b]?`<img src="${appState.bottleImages[b]}" alt="">`:'<span class="no-photo">Nessuna foto</span>'}<b>${esc(appState.bottleNames[b]||'Flacone')}</b><small>${esc(b)}</small><small>Linee: ${(appState.bottleLines[b]||[]).join(', ')||'nessuna'}</small><div class="archive-actions"><button class="primary" onclick="selectBottleFromArchive('${encodeURIComponent(b)}')">Carica sulla linea scelta</button><button onclick="loadBottleCard('${encodeURIComponent(b)}')">Modifica</button><button class="danger" onclick="deleteBottle('${encodeURIComponent(b)}')">Elimina</button></div></div>`).join(''):'<p class="muted">Nessun flacone associato a questa linea.</p>'}</div></details>`}
function bottleCreateForm(title='Crea nuovo codice'){return `<strong class="bottle-editor-title">${esc(title)}</strong><div class="grid bottle-editor-grid"><label class="field">Nome flacone<input id="mapName" placeholder="Es. Shampoo nero"></label><label class="field">Codice flacone<input id="mapBottle" list="bottles" placeholder="Inserisci il codice"></label><label class="field">Foto flacone · galleria o fotocamera<input id="mapPhoto" type="file" accept="image/*,.heic,.heif" onchange="previewBottlePhoto(this)"><small>Su iPhone scegli “Libreria foto” per cercare nella galleria.</small></label></div><fieldset class="bottle-line-picker"><legend>Linee sulle quali usare questo flacone</legend><label class="all-lines"><input id="mapAllLines" type="checkbox" onchange="toggleAllBottleLines(this.checked)"> Seleziona tutte le linee</label><div>${names.map(name=>`<label><input type="checkbox" name="mapBottleLine" value="${name}" ${name===selected?'checked':''}> ${name}</label>`).join('')}</div></fieldset><img id="photoPreview" class="photo-preview" hidden alt="Anteprima foto scelta"><div class="actions"><button class="primary" onclick="saveBottleDetails()">Salva flacone e linee</button></div>`}
