function showBottleEditPicker(){if(!isCT())return toast('Operazione non autorizzata',true);const dialog=bottleEditorShell(`<strong>Modifica codice esistente</strong><p>Inserisci o scegli il codice da modificare.</p><label class="field">Quale codice?<input id="editBottleCode" list="bottles" inputmode="text" placeholder="Es. P015442400"></label>${lists(appState.bottles)}<div class="actions"><button class="primary" id="openBottleEdit">Apri codice</button></div>`);dialog.querySelector('#openBottleEdit').onclick=()=>{const code=dialog.querySelector('#editBottleCode').value.trim();if(!appState.bottles.includes(code))return toast('Codice non trovato nell’archivio',true);dialog.close();showBottleEditDialog(code)};setTimeout(()=>dialog.querySelector('#editBottleCode')?.focus(),100)}
