function lineAssignment(l){const current=l.lineOwnerName?`Affidata a <strong>${esc(l.lineOwnerName)}</strong>`:'Nessuna persona assegnata';if(!isCT())return `<div class="notice">${current}</div>`;return `<div class="notice"><strong>Affidamento linea</strong><p>${current}</p><div class="actions assignment-actions"><select id="lineOwner"><option value="">Nessuna persona</option>${operators.map(o=>`<option value="${o.id}" ${o.id===l.lineOwnerId?'selected':''}>${esc(o.display_name||'Utente')} · ${esc(roleLabels[o.role]||o.role)}</option>`).join('')}</select><button id="assignLine">Conferma assegnazione</button></div></div>`}
