 if(l.stage==='waiting-raclage'){const available=l.bag1+l.bag2,remainingResult=`<div class="notice flow-step remaining-result"><strong>Rimanenza comunicata dall’operatore</strong><h3>${available} big bag disponibil${available===1?'e':'i'}</h3><p>Big bag 1: <b>${l.bag1?'Pieno':'Vuoto'}</b> · Big bag 2: <b>${l.bag2?'Pieno':'Vuoto'}</b><br>Vasca: <b>${vatLabel(l.vatLevel)}</b></p>${isCT()?'<p>Chiama il raclage dal riquadro della linea.</p>':'<p>In attesa della chiamata raclage del CT.</p>'}</div>`;return h+remainingResult+info}
